/**
 * Returns the canonical board name for an id, or undefined if unknown.
 * Wrap the bare number with this when surfacing to users:
 *   `formatBoardId(59)` → "59 (ARK_FPV)"
 *   `formatBoardId(99999)` → "99999"
 */
export function formatBoardId(id: number): string {
  const name = BOARD_NAMES_BY_ID[id]
  return name ? `${id} (${name})` : String(id)
}
